+
+        impl EnvVarGuard {
+            fn set(key: &'static str, value: &str) -> Self {
+                let old = std::env::var(key).ok();
+                set_env(key, value);
+                Self { key, old }
+            }
+        }
+
+        impl Drop for EnvVarGuard {
+            fn drop(&mut self) {
+                if let Some(old) = &self.old {
+                    set_env(self.key, old);
+                } else {
+                    remove_env(self.key);
+                }
+            }
+        }
